The reference solution of that problem in Javascript is 
function solve(chunks, queries) {
    // 1. Concatenate chunks to form string s
    const s = chunks.join('');

    // 2. Use a Map to store the frequency of every maximal word found in s
    const wordCounts = new Map();

    // 3. Extract all maximal contiguous sequences of lowercase letters.
    // Based on the problem constraints and examples, any sequence containing 
    // characters that are not letters or legal hyphens acts as a separator. 
    // Since illegal hyphens act as separators, the maximal words must be contiguous runs of letters.
    const matches = s.match(/[a-z]+/g);

    if (matches) {
        // 4. Count occurrences of each extracted word
        for (const word of matches) {
            wordCounts.set(word, (wordCounts.get(word) || 0) + 1);
        }
    }

    // 5. Generate the result array by looking up counts for each query
    const ans = [];
    for (const query of queries) {
        const count = wordCounts.get(query) || 0;
        ans.push(count);
    }

    return ans;
}

